mapper.select:
select goods.*,type.name as typeName,shopkeeper.shop_name as shopName,IFNULL(saleNum, 0) as saleNum from goods left join type on type.id=goods.type_id left join shopkeeper on shopkeeper.id=goods.shopkeeper_id left join (select goods_id,sum(num) as saleNum from `order` group by goods_id ) as o on o.goods_id=goods.id
and goods.name like concat('%', #{name}, '%')
and goods.type_id = #{typeId}
and goods.shopkeeper_id = #{shopkeeperId}
and goods.status = #{status}
order by id desc

select goods.*,type.name as typeName,IFNULL(saleNum, 0) as saleNum from goods left join type on type.id=goods.type_id left join (select goods_id,sum(num) as saleNum from `order` group by goods_id ) as o on o.goods_id=goods.id
and goods.status = #{status}
order by saleNum desc limit 4

select goods.*,IFNULL(saleNum, 0) as saleNum from goods left join (select goods_id,sum(num) as saleNum from `order` group by goods_id ) as o on o.goods_id=goods.id
and goods.status = #{status}
and goods.shopkeeper_id = #{shopkeeperId}
order by saleNum desc limit 5
